def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        power = 1
        factor = 1
        for j in range(1, 21):
            if j % 3 == 0:
                term = ((-1) ** j) * (ratio ** (j + 1)) / (j ** 2)
                score += term * factor
                factor *= 0.9
            else:
                term = ((-1) ** (j + 1)) * (ratio ** j) / j
                score += term * factor
            power *= 1.01
            if power > 1.5:
                power = 1.0
        if capacity < item * 1.2:
            score *= 2.0
        elif capacity < item * 1.8:
            score *= 1.4
        else:
            for offset in range(1, 4):
                idx = i - offset
                if idx >= 0 and bins[idx] != 0:
                    overlap = item / bins[idx]
                    if 0 < overlap < 1:
                        score += (overlap ** 3) / offset
        penalty = 0
        for k in range(max(0, i - 2), min(n, i + 3)):
            if bins[k] != 0:
                overlap_ratio = item / bins[k]
                if 0 < overlap_ratio < 1:
                    penalty += ((1 - overlap_ratio) ** 3) / ((abs(k - i) + 1) ** 2)
        penalty /= 5
        score_final = -score + penalty
        if score_final < 0:
            score_final = 0
        if capacity - item < 0.1 * item:
            score_final *= 1.25
        priorities[i] = score_final
    return priorities
